#include <bits/stdc++.h>
using namespace std;

int main() {
    ios_base::sync_with_stdio(false); cin.tie(NULL);
    int M, N;
    cin >> M >> N;
    vector<vector<int>> g(N, vector<int>(M));
    queue<pair<int,int>> q;
    for (int i = 0; i < N; i++)
        for (int j = 0; j < M; j++) {
            cin >> g[i][j];
            if (g[i][j] == 1) q.push({i, j});
        }
    int dx[] = {1,-1,0,0};
    int dy[] = {0,0,1,-1};
    int days = 0;
    while (!q.empty()) {
        int sz = q.size();
        bool spread = false;
        for (int s = 0; s < sz; s++) {
            auto [x, y] = q.front(); q.pop();
            for (int d = 0; d < 4; d++) {
                int nx = x + dx[d], ny = y + dy[d];
                if (nx < 0 || ny < 0 || nx >= N || ny >= M) continue;
                if (g[nx][ny] == 0) {
                    g[nx][ny] = 1;
                    q.push({nx, ny});
                    spread = true;
                }
            }
        }
        if (spread) days++;
    }
    for (int i = 0; i < N; i++)
        for (int j = 0; j < M; j++)
            if (g[i][j] == 0) { cout << -1 << "\n"; return 0; }
    cout << days << "\n";
    return 0;
}
